mapper.insert:
Insert INTO wvp_stream_push (app, stream, total_reader_count, origin_type, origin_type_str, create_time, alive_second, media_server_id, status, push_ing)
VALUES 
    (#{item.app}, #{item.stream}, #{item.totalReaderCount}, #{item.originType}
        , #{item.originTypeStr},#{item.createTime}, #{item.aliveSecond}
        , #{item.mediaServerId}, #{item.status}, #{item.pushIng})

mapper.update:
UPDATE wvp_stream_push SET status=0  where (app, stream) in (

    (#{item.app}, #{item.stream})
)

UPDATE wvp_stream_push SET status=1  where (app, stream) in (

    (#{item.app}, #{item.stream})
)

mapper.select:
SELECT st.*, gs.gb_id, gs.name, gs.longitude, gs.latitude, gs.gb_stream_id from wvp_stream_push st LEFT join wvp_gb_stream gs on st.app = gs.app AND st.stream = gs.stream
AND (st.app LIKE concat('%',#{query},'%') OR st.stream LIKE concat('%',#{query},'%') OR gs.gb_id LIKE concat('%',#{query},'%') OR gs.name LIKE concat('%',#{query},'%')) AND (gs.gb_id is null OR st.push_ing=1) AND (st.push_ing is null OR st.push_ing=0) AND st.media_server_id=#{mediaServerId}
order by st.create_time desc

SELECT st.*, gs.gb_id, gs.name, gs.longitude, gs.latitude FROM wvp_stream_push st
    LEFT join wvp_gb_stream gs on st.app = gs.app AND st.stream = gs.stream
WHERE st.app=#{app} AND st.stream=#{stream}
